#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int X,Y; scanf("%d %d",&X,&Y);
        if(Y>=X && Y<=X+200) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

